var webhookData = $input.first().json.body;
var base64Data = webhookData.csvData;
if (!base64Data) {
  throw new Error("No csvData found in request");
}

var datasetName = webhookData.datasetName || "Unnamed Dataset";
var description = webhookData.description || "";
var email = webhookData.email || "";

var csvText = Buffer.from(base64Data, "base64").toString("utf-8");

// Strip BOM if present
if (csvText.charCodeAt(0) === 0xFEFF) {
  csvText = csvText.slice(1);
}

// --- MULTILINE-AWARE CSV PARSER ---
function parseCSV(text) {
  const rows = [];
  let row = [];
  let cell = '';
  let inQuotes = false;

  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    const next = text[i + 1];

    if (char === '"') {
      if (inQuotes && next === '"') {
        cell += '"';
        i++;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      row.push(cell.trim());
      cell = '';
    } else if (!inQuotes && (char === '\n' || char === '\r')) {
      if (char === '\r' && next === '\n') i++;
      row.push(cell.trim());
      if (row.some(v => v !== '')) {
        rows.push(row);
      }
      row = [];
      cell = '';
    } else {
      cell += char;
    }
  }

  // Flush final row
  if (cell || row.length) {
    row.push(cell.trim());
    if (row.some(v => v !== '')) {
      rows.push(row);
    }
  }

  return rows;
}
// ----------------------------------

var allRows = parseCSV(csvText);

if (allRows.length < 2) {
  throw new Error("CSV must have header and data rows");
}

var headers = allRows[0];
var rows = [];

for (var i = 1; i < allRows.length; i++) {
  var values = allRows[i];
  var row = {};
  for (var j = 0; j < headers.length; j++) {
    row[headers[j]] = values[j] !== undefined ? values[j] : "";
  }
  rows.push({ json: row });
}

if (rows.length === 0) {
  throw new Error("No data rows found");
}

$execution.customData.set("datasetName", datasetName);
$execution.customData.set("description", description);
$execution.customData.set("email", email);

return rows;

var datasetRecord = $('Get Dataset Record').first().json;
if (!datasetRecord || !datasetRecord.column_mapping) {
  throw new Error('Dataset not found or missing column_mapping');
}
var mapping = datasetRecord.column_mapping;
var datasetId = $('Webhook').first().json.body.datasetId;
var allRows = $('Parse CSV').all();
var results = [];
var batchSize = 200;
var mapEntries = Object.entries(mapping);
var dbColumnNames = mapEntries.map(function(entry) { return entry[1]; });

function isDateColumn(colName) {
  var lower = colName.toLowerCase();
  var datePatterns = ['date', 'time', 'created', 'updated', 'timestamp', 'modified', 'expires', 'born', 'started', 'ended', 'due', 'scheduled', '_at', '_on'];
  for (var i = 0; i < datePatterns.length; i++) {
    if (lower.indexOf(datePatterns[i]) !== -1) {
      return true;
    }
  }
  return false;
}

function isValidDateValue(val) {
  var stringVal = String(val).trim();
  // Pure numbers > 9999 are not valid dates (except Unix timestamps which we won't support here)
  if (/^\d+$/.test(stringVal) && parseInt(stringVal) > 9999) {
    return false;
  }
  // Must contain at least one separator for date formats
  if (stringVal.indexOf('/') !== -1 || stringVal.indexOf('-') !== -1) {
    return true;
  }
  // 4-digit number could be a year, but alone it's not a complete date
  if (/^\d{1,4}$/.test(stringVal)) {
    return false;
  }
  return false;
}

function formatDateValue(val) {
  var stringVal = String(val).trim();
  var dateMatch = stringVal.match(/^(\d{1,4})[\/\-](\d{1,2})[\/\-](\d{1,4})(.*)$/);
  if (!dateMatch) return null;

  var part1 = dateMatch[1];
  var part2 = dateMatch[2];
  var part3 = dateMatch[3];
  var timePart = dateMatch[4] || '';

  var year, month, day;
  if (part1.length === 4) {
    year = part1; month = part2; day = part3;
  } else if (part3.length === 4) {
    year = part3;
    if (parseInt(part1) > 12) { day = part1; month = part2; }
    else { month = part1; day = part2; }
  } else {
    year = parseInt(part3) > 50 ? '19' + part3 : '20' + part3;
    month = part1; day = part2;
  }

  month = ('0' + month).slice(-2);
  day = ('0' + day).slice(-2);
  return year + '-' + month + '-' + day + timePart;
}

function prepareValue(val, dbColumn) {
  if (val === null || val === undefined || String(val).trim() === '') {
    return 'NULL';
  }
  var stringVal = String(val).trim();

  if (isDateColumn(dbColumn)) {
    if (!isValidDateValue(stringVal)) {
      return 'NULL';
    }
    var formatted = formatDateValue(stringVal);
    if (formatted) {
      return "'" + formatted.replace(/'/g, "''") + "'";
    }
    return 'NULL';
  }

  return "'" + stringVal.replace(/'/g, "''") + "'";
}

var columns = ['"dataset_id"', '"row_index"'].concat(dbColumnNames.map(function(c) { return '"' + c + '"'; }));

for (var i = 0; i < allRows.length; i += batchSize) {
  var chunk = allRows.slice(i, i + batchSize);
  var valuesList = chunk.map(function(item, idx) {
    var row = item.json;
    var rowValues = ["'" + datasetId + "'", i + idx + 1];
    mapEntries.forEach(function(entry) {
      rowValues.push(prepareValue(row[entry[0]], entry[1]));
    });
    return '(' + rowValues.join(',') + ')';
  });
  results.push({ json: { sql: 'INSERT INTO n8n_data.universal_datatable (' + columns.join(',') + ') VALUES ' + valuesList.join(',') + ';' } });
}

return results;

